head.script:
/**
 * 화 면 명 : 업무용차량 등록
 * 메뉴경로 : 공통/총무업무/업무용 차량관리/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/ps/rc/fms/imgnt/rc_605_01_04b.jsp
 * 작 성 자 : 정승혜
 * 작 업 일 : 2025-12-08
 * 수정이력  :
 *    - 2025-12-08      정승혜    최초작성
 *    - 2026-03-04      정승혜    기타수정
 * 메모 :
 * txt_ctrtVehclSeq 쓰이는곳 없음
 * 조회조건 : 
 * 
 */
scwin.strFromDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.strPreDate = $c.date.addDate(scwin.strFromDate, -1 );
scwin.strNextDate = $c.date.addDate(scwin.strFromDate, 1 );

scwin.memJson = $c.data.getMemInfo();
scwin.clntNo = scwin.memJson.clntNo;
scwin.clntNm = scwin.memJson.clntNm;
scwin.userId = scwin.memJson.userId;
scwin.userNm = scwin.memJson.userNm;

scwin.inUpFlag   = false;	// 신규, 수정버튼 구분
scwin.pos_rowSts = 0;		// 수정 후 컬럼이동

//hidden
scwin.hid_seq = "";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    scwin.f_setDtheader_results();

    // getCodeList
    const codeOptions = [
        { grpCd : "ZZ604", compID : "lc_fuelKndCd" },
    ];
    $c.data.setCommonCode(codeOptions);

};

// UDC값 초기화(scwin.onpageload 이후 세팅됨)
scwin.onUdcCompleted = function() {
    $c.gus.cfDisableBtn([$c.gus.getctrlBtn('b_Update')]);
    $c.gus.cfDisableBtn([$c.gus.getctrlBtn('b_Cancel')]);
    $c.gus.cfDisableBtn([$c.gus.getctrlBtn('b_Delete')]);

    // 키값을 제외한 나머지 일반 데이터를 편집을 불가능 하게 한다. 
    $c.gus.cfDisableKeyData();

    // 우편번호 팝업 비활성화 
    $c.gus.cfDisableObjects(btn_busiZip);

    scwin.setInsertHeader();    

    scwin.f_Retrieve();   
};

//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
// 엑셀다운 2+8+16
scwin.f_runExcel = async function() {
    let totCnt = ds_vehclInfo.getRowCount();
    if(totCnt != 0) {
        const options = {
            fileName : "차량별 운행실적.xlsx", 
            sheetName : "차량별 운행실적",
        }
        let confirm  = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (confirm) {
            $c.data.downloadGridViewExcel(gr_vehclInfo, options);
        }  
    }else{
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }
};

//-------------------------------------------------------------------------
// 조회조건 header Setting
//-------------------------------------------------------------------------
scwin.f_setDtheader_results = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

scwin.setInsertHeader = function() {
    // DataSet의 Header 정보 생성(TODO:TOBE 데이터맵으로 셋팅하므로 필요없음)
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    scwin.inUpFlag = false;

	$c.gus.cfDisableKeyData();

    let ret = await $c.gus.cfValidate([tbl_search]);
    if (!ret){
        return;
    }

    dma_Retrieve.set( "deptCd", p_ed_srcDeptNo.getValue() );    // 부서코드 // ed_qryCntn
    dma_Retrieve.set( "vehcelNo", p_ed_vehcelNo.getValue() );   // 차량번호
    dma_Retrieve.set( "vehcelNm", p_ed_vehcelNm.getValue() );   // 차량명
    dma_Retrieve.set( "selfYn", p_lc_selfYn.getValue() );       // 차량구분[자가/임차/리스]
    dma_Retrieve.set( "useYn", p_lc_useYn.getValue())
    dma_Retrieve.set( "costMgntYn", p_lc_costMgntYn.getValue() );
    dma_Retrieve.set( "stDt", ed_stDt.getValue() );
    dma_Retrieve.set( "edDt", ed_edDt.getValue() );

    if ( ed_stDt.getValue() != "" || ed_edDt.getValue() != "") {
        if (ed_stDt.getValue() < "19000101") { 
            await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,"사용기간From")); //을(를) 입력하십시오.
            ed_stDt.setValue("");
            ed_stDt.focus();
	    	return;
	    }
        if (ed_edDt.getValue() < "19000101") {     
            await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,"사용기간To")); //을(를) 입력하십시오.
            ed_edDt.setValue("");
            ed_edDt.focus();
	    	return;
	    }
	    if ( ed_stDt.getValue() > ed_edDt.getValue()) {
			await $c.gus.cfAlertMsg(MSG_CM_ERR_039);  //시작일자를 종료일자 이전으로 선택[입력]하여주십시요.
	    	return;
		}
	}

	$c.sbm.execute(sbm_tr_retrieve);
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {

    scwin.pos_rowSts = ds_vehclInfo.getRowPosition();	

	if (!ds_vehclInfo.getModifiedIndex().length > 0) {
        await $c.win.alert("변경된 내용이 없습니다.");
        return;
    }

	for (j = 0; j < ds_vehclInfo.getRowCount(); j++) {	
		if (ds_vehclInfo.getRowStatus(j) == "C" || ds_vehclInfo.getRowStatus(j) == "U") {  

		    if (ds_vehclInfo.getCellData(j, "ctrtNo") == "" || ds_vehclInfo.getCellData(j, "ctrtNo") == "99999999999") {	
		    	if (ds_vehclInfo.getCellData(j, "vehclNo") == ""){		    		
			        await $c.win.alert(j+1 + "번째 차량번호를 정확히 입력하십시오.");
			        ed_vehclNo.focus();
			        return;
			    }
		    } else {
			    if (ds_vehclInfo.getCellData(j, "vehclNo") == "" || ds_vehclInfo.getCellData(j, "shortCd") == ""){
			    	await $c.win.alert(j+1 + "번째 차량번호를 정확히 입력하십시오.");
			        ed_vehclNo.focus();			    	
			        return;
			    }
		    }

		    if (ds_vehclInfo.getCellData(j, "userId") == "") {
		        await $c.win.alert(j+1 + "번째 사용자 정보를 정확히 입력하십시오.");
		        ed_userId.focus();		        
		        return;
		    }

		    if (ds_vehclInfo.getCellData(j, "carVolume") == "") {
		        await $c.win.alert(j+1 + "번째 배기량 정보를 정확히 입력하십시오.");
		        ed_carVolume.focus();
		        return;
		    }

		    if (ds_vehclInfo.getCellData(j, "leaseAmt") == "") {
		        await $c.win.alert(j+1 + "번째 대여료 정보를 정확히 입력하십시오.");
		        ed_leaseAmt.focus();
		        return;
		    }		    		   
		    if (ds_vehclInfo.getCellData(j, "fuelKndCd") == "") {
		        await $c.win.alert(j+1 + "번째 연료 정보를 정확히 입력하십시오.");
		        lc_fuelKndCd.focus();
		        return;
		    }		    		    
		    if (!$c.gus.cfIsAfterDate(ds_vehclInfo.getCellData(j, "ctrtStDt").trim(), ds_vehclInfo.getCellData(j, "ctrtEndDt").trim())) {
	    		await $c.win.alert(j+1 + "번째 " + MSG_CM_ERR_039); 
	    		ed_dtFrom.focus();
	    		return;
	      	}

	      	// 비용신고차량인 경우 : 계약기간 필수입력
	      	if ( ds_vehclInfo.getCellData(j, "costMgntYn") == "Y" ) {
	      		if ( ds_vehclInfo.getCellData(j, "ctrtStDt") == "" ||  ds_vehclInfo.getCellData(j, "ctrtEndDt") == "" ) {
	      			await $c.win.alert(j+1 + "번째 비용신고대상 차량이므로 사용기간을 입력하십시오.");
	      			ed_dtFrom.focus();
	      			return;
	      		}
	      	}
		}
	}

    let confirm  = await $c.win.confirm("저장하시겠습니까?");
    if (confirm) {
        $c.sbm.execute(sbm_tr_save); 
    }  
};

 //-------------------------------------------------------------------------
 // 조회조건 필드 Clear
