//공통 PopUp 호출
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch, row) {
    if(row == null){
       row = 0;
    }

    switch (disGubun)
    {
        case 1:
        // 사용자
            udc_userInfo.cfCommonPopUp(scwin.udc_userInfo_callBackFunc
                ,pCode// 화면에서의 ??? Code Element의Value
                ,pName// 화면에서의 ??? Name Element의Value
                ,pClose // 결과가 1건 일때원도우를AutoClose 여부(T:Close,F:Opened)
                ,null // 검색 결과컬럼의 보여주는개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null // Title순서
                ,null // 보여주는 각 컬럼들의 폭
                ,null // 컬럼중에서 숨기는컬럼 지정 
                ,null // SQL절의 WHERE절에원하는 조건을 선택함 MAX:8개까지 가능
                ,null // POP-UP뛰을때 원도우의 사용자 정의폭
                ,null // POP-UP뛰을때 우도우의 사용자 정의높이
                ,null // 윈도우 위치 Y좌표 
                ,null // 윈도우 위치 X좌표
                ,null // 중복체크여부 ("F")
                ,pAllSearch // 전체검색허용여부 ("F")
                ,null // POP-UP Window Title 검색어1,2("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;

        case 2:
        // 관리부서
            udc_acctDeptCdInfo2.cfCommonPopUp(scwin.udc_acctDeptCdInfo2_callBackFunc
                ,pCode                  // 화면에서의 ??? Code Element의  Value
                ,pName                  // 화면에서의 ??? Name Element의  Value
                ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null                   // Title순서  
                ,null                   // 보여주는 각 컬럼들의 폭    
                ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                ,null                   // 윈도우 위치 Y좌표   
                ,null                   // 윈도우 위치 X좌표
                ,null                   // 중복체크여부   ("F")
                ,pAllSearch             // 전체검색허용여부 ("F")
                ,null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;

        case 3:
        // 부서
            udc_acctDeptCdInfo.cfCommonPopUp(scwin.udc_acctDeptCdInfo_callBackFunc
                ,pCode                  // 화면에서의 ??? Code Element의  Value
                ,pName                  // 화면에서의 ??? Name Element의  Value
                ,pClose                 // 결과가 1건 일때  원도우를  AutoClose 여부    (T:Close,F:Opened)
                ,null                   // 검색 결과    컬럼의 보여주는    개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null                   // Title순서  
                ,null                   // 보여주는 각 컬럼들의 폭    
                ,null                   // 컬럼중에서 숨기는    컬럼 지정   
                ,null                   // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                ,null                   // POP-UP뛰을때 원도우의   사용자 정의  폭
                ,null                   // POP-UP뛰을때 우도우의   사용자 정의  높이  
                ,null                   // 윈도우 위치 Y좌표   
                ,null                   // 윈도우 위치 X좌표
                ,null                   // 중복체크여부   ("F")
                ,pAllSearch             // 전체검색허용여부 ("F")
                ,null                   // POP-UP Window Title 검색어1,2    ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
        break;

        case 4:
        // 계약부서
            udc_acctDeptCdInfo3.cfCommonPopUp(scwin.udc_acctDeptCdInfo3_callBackFunc
